// ─── Arrays in JavaScript ───────────────────────────────────────────────────
//
// JavaScript arrays are dynamic — they resize automatically and can hold
// mixed types. Under the hood, V8 uses a contiguous block for uniform
// integer/float arrays (fast path) and falls back to a hash-map for
// mixed/sparse arrays (slow path). Stick to one type for best performance.

const arr = [10, 20, 30, 40];

// ── O(1) — Read by index ─────────────────────────────────────────────────
// The runtime computes: base_address + index * element_size
// One memory read, regardless of array length.
const x = arr[2];          // x = 30
console.log(x);            // 30

// ── O(1) — Update by index ───────────────────────────────────────────────
// Same address arithmetic as read, then a single write.
arr[1] = 25;               // [10, 25, 30, 40]

// ── O(1) amortized — Push (append to end) ────────────────────────────────
// When the internal buffer has room, this is a single write.
// When the buffer is full, JS allocates ~2× space and copies (O(n)),
// but that happens so rarely the average cost stays O(1).
arr.push(50);              // [10, 25, 30, 40, 50]

// ── O(1) amortized — Pop (remove from end) ───────────────────────────────
// Decrements the length; no elements need to move.
const last = arr.pop();    // last = 50, arr = [10, 25, 30, 40]

// ── O(n) — Insert at arbitrary index ─────────────────────────────────────
// splice() shifts every element after the insertion point one slot right.
// Worst case: insert at index 0 → all n elements move.
arr.splice(1, 0, 15);      // [10, 15, 25, 30, 40]  (inserted 15 at index 1)

// ── O(n) — Delete at arbitrary index ─────────────────────────────────────
// splice() shifts every element after the deletion point one slot left.
arr.splice(2, 1);          // [10, 15, 30, 40]  (removed 25 at index 2)

// ── O(n) — Linear search ─────────────────────────────────────────────────
// indexOf scans left-to-right until it finds the value (or hits the end).
// Best case O(1) (first element), worst case O(n) (last or absent).
const idx = arr.indexOf(30); // 2

// ── Practical patterns ───────────────────────────────────────────────────

// Two-pointer technique — O(n), O(1) space
function twoSum(nums, target) {
  let left = 0, right = nums.length - 1;
  while (left < right) {
    const sum = nums[left] + nums[right];
    if (sum === target) return [left, right];
    sum < target ? left++ : right--;
  }
  return [];
}

// Sliding window — O(n), O(1) space
function maxSubarraySum(nums, k) {
  let windowSum = nums.slice(0, k).reduce((a, b) => a + b, 0);
  let max = windowSum;
  for (let i = k; i < nums.length; i++) {
    windowSum += nums[i] - nums[i - k];
    max = Math.max(max, windowSum);
  }
  return max;
}

// Prefix sums — O(n) build, O(1) range queries
function buildPrefix(nums) {
  const prefix = [0];
  for (const n of nums) prefix.push(prefix.at(-1) + n);
  return prefix;
}
// Range sum [l, r] in O(1) after prefix is built:
// rangeSum = prefix[r + 1] - prefix[l]

// ─── Arrays in Java ──────────────────────────────────────────────────────────
//
// Java has two array flavours:
//   int[] / T[]      — fixed-size, allocated once, O(1) access, no resize.
//   ArrayList<T>     — dynamic wrapper around Object[], auto-resizes (×1.5).
//
// Prefer int[] when size is known upfront; ArrayList when you need add/remove.

import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;

public class ArrayOps {

    public static void main(String[] args) {

        // ── Fixed-size primitive array ────────────────────────────────────
        int[] arr = {10, 20, 30, 40};

        // O(1) — Read by index
        int x = arr[2];          // 30

        // O(1) — Update by index
        arr[1] = 25;             // [10, 25, 30, 40]

        // O(n) — Copy to a larger array (manual "insert")
        // Java arrays cannot resize; you must allocate a new array.
        int insertAt = 1, insertVal = 15;
        int[] larger = new int[arr.length + 1];
        System.arraycopy(arr, 0, larger, 0, insertAt);
        larger[insertAt] = insertVal;
        System.arraycopy(arr, insertAt, larger, insertAt + 1, arr.length - insertAt);
        // larger = [10, 15, 25, 30, 40]

        // ── ArrayList — dynamic, resizable ───────────────────────────────
        ArrayList<Integer> list = new ArrayList<>(List.of(10, 20, 30, 40));

        // O(1) — Read by index
        int val = list.get(2);          // 30

        // O(1) — Update by index
        list.set(1, 25);                // [10, 25, 30, 40]

        // O(1) amortized — Append to end
        // When internal array is full, ArrayList grows to 1.5× capacity,
        // copies all elements, then writes. Rare, so average stays O(1).
        list.add(50);                   // [10, 25, 30, 40, 50]

        // O(1) amortized — Remove from end
        list.remove(list.size() - 1);  // [10, 25, 30, 40]

        // O(n) — Insert at arbitrary index (shifts elements right)
        list.add(1, 15);               // [10, 15, 25, 30, 40]

        // O(n) — Delete at arbitrary index (shifts elements left)
        list.remove(2);                // [10, 15, 30, 40]

        // O(n) — Linear search
        int idx = list.indexOf(30);    // 2

        // ── Arrays utility class ──────────────────────────────────────────
        int[] nums = {4, 2, 7, 1, 9};
        Arrays.sort(nums);             // O(n log n) — [1, 2, 4, 7, 9]
        int pos = Arrays.binarySearch(nums, 7); // O(log n) — requires sorted
        int[] copy = Arrays.copyOfRange(nums, 1, 4); // O(k) — [2, 4, 7]
    }

    // ── Two-pointer — O(n), O(1) space ───────────────────────────────────
    static int[] twoSum(int[] nums, int target) {
        int left = 0, right = nums.length - 1;
        while (left < right) {
            int sum = nums[left] + nums[right];
            if (sum == target)  return new int[]{left, right};
            else if (sum < target) left++;
            else                   right--;
        }
        return new int[]{};
    }

    // ── Prefix sums — O(n) build, O(1) range query ───────────────────────
    static int[] buildPrefix(int[] nums) {
        int[] prefix = new int[nums.length + 1];
        for (int i = 0; i < nums.length; i++)
            prefix[i + 1] = prefix[i] + nums[i];
        return prefix;
    }
    // rangeSum(l, r) = prefix[r + 1] - prefix[l]
}

// ─── Arrays in C++ ───────────────────────────────────────────────────────────
//
// C++ offers three layers:
//   int arr[N]         — stack-allocated, compile-time size, raw speed.
//   std::array<T, N>   — zero-overhead wrapper, same fixed size, safer API.
//   std::vector<T>     — heap-allocated dynamic array; the everyday choice.
//
// Prefer vector<T> unless you have a size-at-compile-time constraint.

#include <algorithm>
#include <iostream>
#include <numeric>
#include <vector>

int main() {

    // ── std::vector — dynamic array ───────────────────────────────────────
    std::vector<int> arr = {10, 20, 30, 40};

    // O(1) — Read / update by index (no bounds check)
    int x   = arr[2];      // 30
    arr[1]  = 25;          // [10, 25, 30, 40]

    // O(1) — Read / update with bounds checking (throws std::out_of_range)
    int y   = arr.at(2);   // 30

    // O(1) amortized — Append to end
    // vector doubles its capacity when full; push_back copies/moves one element.
    arr.push_back(50);     // [10, 25, 30, 40, 50]

    // O(1) — Remove from end (no reallocation, just decrements size)
    arr.pop_back();        // [10, 25, 30, 40]

    // O(n) — Insert at arbitrary position
    // iterator arithmetic: begin() + 1 points to index 1
    arr.insert(arr.begin() + 1, 15);   // [10, 15, 25, 30, 40]

    // O(n) — Erase at arbitrary position
    arr.erase(arr.begin() + 2);        // [10, 15, 30, 40]

    // O(n) — Linear search (returns iterator, not index)
    auto it = std::find(arr.begin(), arr.end(), 30);
    if (it != arr.end()) {
        int idx = std::distance(arr.begin(), it); // 2
    }

    // ── Reserve capacity upfront to avoid reallocations ──────────────────
    std::vector<int> big;
    big.reserve(1000);          // allocates space, size stays 0
    for (int i = 0; i < 1000; i++) big.push_back(i); // zero reallocations

    // ── Algorithms (work on any contiguous range) ─────────────────────────
    std::sort(arr.begin(), arr.end());                  // O(n log n)
    bool found = std::binary_search(arr.begin(), arr.end(), 30); // O(log n)
    int  total = std::accumulate(arr.begin(), arr.end(), 0);     // O(n)

    // ── Two-pointer — O(n), O(1) space ───────────────────────────────────
    auto twoSum = [](std::vector<int>& nums, int target) {
        int l = 0, r = (int)nums.size() - 1;
        while (l < r) {
            int s = nums[l] + nums[r];
            if      (s == target) return std::make_pair(l, r);
            else if (s < target)  l++;
            else                  r--;
        }
        return std::make_pair(-1, -1);
    };

    // ── Prefix sums — O(n) build, O(1) range queries ─────────────────────
    std::vector<int> prefix(arr.size() + 1, 0);
    for (int i = 0; i < (int)arr.size(); i++)
        prefix[i + 1] = prefix[i] + arr[i];
    // rangeSum(l, r) = prefix[r + 1] - prefix[l]

    return 0;
}
